import React, { useEffect, useState } from "react";
import axios from "axios";
import { Line, Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend
);

export default function Reportes() {
  const [ventasDia, setVentasDia] = useState([]);
  const [ventasMes, setVentasMes] = useState([]);
  const [cargando, setCargando] = useState(false);

  useEffect(() => {
    obtenerReportes();
  }, []);

  const obtenerReportes = async () => {
    setCargando(true);
    try {
      const resDia = await axios.get("http://localhost:5000/api/reportes/dia");
      const resMes = await axios.get("http://localhost:5000/api/reportes/mes");
      setVentasDia(resDia.data);
      setVentasMes(resMes.data);
    } catch (error) {
      console.error("Error al obtener reportes:", error);
    } finally {
      setCargando(false);
    }
  };

  const dataDia = {
    labels: ventasDia.map((v) => new Date(v.Dia).toLocaleDateString()),
    datasets: [
      {
        label: "Total Ventas ($)",
        data: ventasDia.map((v) => v.TotalVentas),
        borderColor: "rgb(75, 192, 192)",
        backgroundColor: "rgba(75, 192, 192, 0.2)",
      },
      {
        label: "Productos Vendidos",
        data: ventasDia.map((v) => v.TotalProductosVendidos),
        borderColor: "rgb(255, 99, 132)",
        backgroundColor: "rgba(255, 99, 132, 0.2)",
      },
    ],
  };

  const dataMes = {
    labels: ventasMes.map((v) => `${v.Mes}/${v.Anio}`),
    datasets: [
      {
        label: "Total Ventas ($)",
        data: ventasMes.map((v) => v.TotalVentas),
        backgroundColor: "rgba(54, 162, 235, 0.5)",
      },
      {
        label: "Productos Vendidos",
        data: ventasMes.map((v) => v.TotalProductosVendidos),
        backgroundColor: "rgba(255, 206, 86, 0.5)",
      },
    ],
  };

  return (
    <div className="container mt-5">
      <h2 className="mb-4">Reportes de Ventas</h2>
      {cargando ? (
        <p>Cargando reportes...</p>
      ) : (
        <>
          <div className="mb-5">
            <h4>Ventas por Día</h4>
            <Line data={dataDia} />
          </div>
          <div className="mb-5">
            <h4>Ventas por Mes</h4>
            <Bar data={dataMes} />
          </div>
        </>
      )}
    </div>
  );
}
